UPDATE BRD_POST_MST
   SET comment_cnt = (
           SELECT COUNT(*)
             FROM BRD_POST_COMMENT
            WHERE post_no = #{postNo}
              AND del_yn  = 'N'
       )
 WHERE post_no = #{postNo}
